// items[0] = federated webhook response
// items[1] = open tasks query response

const items = $input.all();
const fed = items[0].json;
const openTasks = items[1].json;

// Build set of source URLs already harvested (extracted from Notes/Source fields)
const existingSourceUrls = new Set();
for (const page of (openTasks.results || [])) {
  const props = page.properties || {};
  const notes = ((props.Notes && props.Notes.rich_text) || []).map(t => t.plain_text || '').join('');
  const source = ((props.Source && props.Source.rich_text) || []).map(t => t.plain_text || '').join('');
  const combined = `${notes}\n${source}`;
  for (const m of combined.matchAll(/https:\/\/www\.notion\.so\/[A-Za-z0-9\-]+/g)) {
    existingSourceUrls.add(m[0]);
  }
}

// Canonical meeting list: prefer CRM side when paired (Sales User's notes go there)
const meetings = [];
for (const p of (fed.pairs || [])) {
  meetings.push({ primary: p.zr, secondary: p.re, paired: true });
}
for (const m of (fed.unpaired_sample_company || [])) meetings.push({ primary: m, secondary: null, paired: false });
for (const m of (fed.unpaired_recall || [])) meetings.push({ primary: m, secondary: null, paired: false });

function extractPageId(notionUrl) {
  if (!notionUrl) return null;
  const m = notionUrl.match(/([0-9a-f]{32})(?:\?|$)/i);
  if (!m) return null;
  const h = m[1];
  return `${h.slice(0,8)}-${h.slice(8,12)}-${h.slice(12,16)}-${h.slice(16,20)}-${h.slice(20)}`;
}

// v1.2: For PAIRED meetings, prefer Recall as primary (structured Actions table).
// For UNPAIRED CRM, keep CRM (LLM extract path).
// For UNPAIRED Recall, parse Actions table directly.
const toProcess = [];
const skipped = [];
for (const meeting of meetings) {
  let primary = meeting.primary;
  let secondary = meeting.secondary;
  // For paired meetings, swap so Recall is primary
  if (meeting.paired && primary && primary.side === 'sample_company' && secondary && secondary.side === 'recall') {
    primary = meeting.secondary;
    secondary = meeting.primary;
  }
  if (!primary || !primary.notion_url) { skipped.push({reason:'no primary', meeting}); continue; }
  if (existingSourceUrls.has(primary.notion_url)) { skipped.push({reason:'already harvested (primary)', title: primary.title, url: primary.notion_url}); continue; }
  // Also dedupe if the secondary URL has been harvested in a prior run
  if (secondary && secondary.notion_url && existingSourceUrls.has(secondary.notion_url)) { skipped.push({reason:'already harvested (secondary)', title: primary.title, url: primary.notion_url}); continue; }
  const pageId = primary.id || extractPageId(primary.notion_url);
  if (!pageId) { skipped.push({reason:'no page id', title: primary.title}); continue; }
  toProcess.push({
    page_id: pageId,
    notion_url: primary.notion_url,
    title: primary.title,
    start_iso: primary.start_iso,
    attendees: primary.attendees,
    company: primary.company,
    side: primary.side,
    paired: meeting.paired,
    paired_with_url: secondary ? secondary.notion_url : null,
    paired_with_title: secondary ? secondary.title : null,
  });
}

return { to_process: toProcess, skipped, skipped_count: skipped.length, to_process_count: toProcess.length, existing_sources_count: existingSourceUrls.size };

// Parse Recall page's `## Actions` markdown table directly — no LLM.
// Recall pages are populated by the Agendino pipeline with a top-level structured table.

function blocksToText(blocks) {
  let out = '';
  for (const b of blocks || []) {
    const t = b.type; if (!b[t]) continue;
    const rt = (b[t].rich_text || []).map(r => r.plain_text || '').join('');
    if (t === 'paragraph') out += `${rt}\n`;
    else if (t === 'heading_1') out += `\n# ${rt}\n`;
    else if (t === 'heading_2') out += `\n## ${rt}\n`;
    else if (t === 'heading_3') out += `\n### ${rt}\n`;
    else if (t === 'bulleted_list_item') out += `- ${rt}\n`;
    else if (t === 'numbered_list_item') out += `1. ${rt}\n`;
    else if (t === 'table_row') {
      const cells = (b.table_row.cells || []).map(c => c.map(x => x.plain_text || '').join('')).join(' | ');
      out += `| ${cells} |\n`;
    } else if (rt) out += `${rt}\n`;
  }
  return out;
}

function normalizeOwner(raw) {
  if (!raw) return 'Unassigned';
  // "Speaker A (External Contact)" → "External Contact". "Speaker A & Speaker B (Sales User)" → "Sales User" if last paren-name.
  const cleaned = raw.trim();
  if (/^Sales User/i.test(cleaned)) return 'Sales User';
  const parens = [...cleaned.matchAll(/\(([^)]+)\)/g)].map(m => m[1].trim()).filter(Boolean);
  if (parens.length === 0) {
    // No parens — return as-is if not a speaker label, else Unassigned
    if (/^speaker\s+[a-z]/i.test(cleaned)) return 'Unassigned';
    return cleaned.slice(0, 60);
  }
  // Look for Sales User first in any paren
  const salesUserLike = parens.find(p => /Sales User/i.test(p));
  if (salesUserLike) return 'Sales User';
  return parens[0].slice(0, 60);
}

function parseDeadline(raw) {
  if (!raw) return null;
  const s = raw.trim();
  if (/not specified|tbd|n\/a|none/i.test(s)) return null;
  // ISO date present?
  const iso = s.match(/(\d{4}-\d{2}-\d{2})/);
  if (iso) return iso[1];
  return null; // could add fuzzy parsing later
}

const meeting = $('Split meetings').item.json;
const blocks = $json.results || [];
const bodyText = blocksToText(blocks);

// Find the Actions section
const actionsIdx = bodyText.toLowerCase().indexOf('## actions');
let ais = [];
let summary = '';

// Try to capture a one-sentence summary from a 'Meeting Overview' or first paragraph
const overview = bodyText.match(/##\s*Meeting Overview\s*\n+([^\n#]+)/i);
if (overview) summary = overview[1].trim().slice(0, 180);

if (actionsIdx === -1) {
  return { skip: true, reason: 'no Actions section in Recall page', meeting, body_length: bodyText.length };
}

const actionsSection = bodyText.slice(actionsIdx);
const tableLines = actionsSection.split('\n').filter(l => l.trim().startsWith('|'));
if (tableLines.length < 3) {
  return { skip: true, reason: 'Actions section has no table', meeting, body_length: bodyText.length };
}

// Skip header (line 0) and separator (line 1)
for (const line of tableLines.slice(2)) {
  let cells = line.split('|').slice(1, -1).map(c => c.trim());
  if (cells.length < 2) continue;
  // Auto-detect leading row-number column: if cells[0] is just digits, shift it off
  if (/^\d+$/.test(cells[0])) cells.shift();
  // Expected (after shift): Title | Description | Owner | Deadline | Notes
  const [title = '', desc = '', owner = '', deadline = '', notes = ''] = cells;
  const text = (title || desc).trim();
  if (!text || /^-+$/.test(text)) continue;
  ais.push({
    text: text.slice(0, 200),
    owner: normalizeOwner(owner),
    due_date: parseDeadline(deadline),
    context: (notes || desc).trim().slice(0, 200),
  });
}

if (ais.length === 0) {
  return { skip: true, reason: 'no AIs parsed from Recall table', meeting, body_length: bodyText.length };
}

// Build the Open Tasks row — same shape as the CRM path
const meetingDate = (meeting.start_iso || '').slice(0, 10) || 'no date';
const ownerSet = [...new Set(ais.map(a => a.owner || 'Unassigned'))];
const titleBase = (((ais[0] || {}).text || '').trim() + (ais.length > 1 ? ' (+' + (ais.length - 1) + ' more)' : '')).slice(0, 190);

const notesLines = [];
notesLines.push(`Source URL: ${meeting.notion_url}`);
notesLines.push(`Source side: Recall (HiDock field recording)`);
if (meeting.paired_with_url) notesLines.push(`Notetaker URL: ${meeting.paired_with_url}`);
if (meeting.paired_with_title) notesLines.push(`Notetaker title: ${meeting.paired_with_title}`);
notesLines.push(`Meeting date: ${meetingDate}`);
notesLines.push(`Attendees: ${(meeting.attendees || '').slice(0, 200)}`);
if (summary) notesLines.push(`Summary: ${summary}`);
notesLines.push('');
notesLines.push('Action items (from Recall Actions table):');
for (const a of ais) {
  const due = a.due_date ? ` (due ${a.due_date})` : '';
  notesLines.push(`- [${a.owner}] ${a.text}${due}${a.context ? ` — ${a.context}` : ''}`);
}
const notesText = notesLines.join('\n').slice(0, 1990);

const properties = {
  Task: { title: [{ text: { content: titleBase } }] },
  Status: { status: { name: 'Not started' } },
  Source: { rich_text: [{ text: { content: `Recall meeting: ${meeting.title}`.slice(0, 190) } }] },
  Notes: { rich_text: [{ text: { content: notesText } }] },
};

return {
  skip: false,
  meeting,
  ai_count: ais.length,
  owners: ownerSet,
  notion_payload: {
    parent: { data_source_id: 'REPLACE_WITH_DATA_SOURCE_ID' },
    properties,
  },
  preview: { title: titleBase, notes: notesText.slice(0, 300) },
};

// Identify the first block with has_children (Notetaker's transcription block).
// Falls back to the page id so the next HTTP node always has a valid URL.
const top = $json.results || [];
const meeting = $('Split meetings').item.json;
const child = top.find(b => b && b.has_children);
return {
  meeting,
  top_blocks: top,
  child_block_id: child ? child.id : null,
  child_block_type: child ? child.type : null,
  fetch_id: child ? child.id : meeting.page_id,
};

// Find the first L2 block with has_children — for Notetaker, this is the `summary` container.
// Fallback to picking the page id (no-op fetch) if no L2 children exist.
const meeting = $('Pick child block').item.json.meeting;
const topBlocks = $('Pick child block').item.json.top_blocks || [];
const l2Blocks = $json.results || [];
const child = l2Blocks.find(b => b && b.has_children);
return {
  meeting,
  top_blocks: topBlocks,
  l2_blocks: l2Blocks,
  grandchild_block_id: child ? child.id : null,
  grandchild_block_type: child ? child.type : null,
  fetch_id: child ? child.id : meeting.page_id,
};

// Convert Notion blocks (recursively) to markdown; attach LLM prompt.
// Runs once per input item — $json = current blocks-fetch response, paired with Split meetings.

function blocksToText(blocks, depth) {
  let out = '';
  const indent = '  '.repeat(depth || 0);
  for (const b of blocks || []) {
    const t = b.type;
    if (!b[t]) continue;
    const rt = (b[t].rich_text || []).map(r => r.plain_text || '').join('');
    if (t === 'paragraph') out += `${indent}${rt}\n`;
    else if (t === 'heading_1') out += `\n# ${rt}\n`;
    else if (t === 'heading_2') out += `\n## ${rt}\n`;
    else if (t === 'heading_3') out += `\n### ${rt}\n`;
    else if (t === 'bulleted_list_item') out += `${indent}- ${rt}\n`;
    else if (t === 'numbered_list_item') out += `${indent}1. ${rt}\n`;
    else if (t === 'to_do') out += `${indent}- [ ] ${rt}\n`;
    else if (t === 'quote') out += `${indent}> ${rt}\n`;
    else if (t === 'toggle') out += `${indent}▾ ${rt}\n`;
    else if (t === 'code') out += `\n\`\`\`\n${rt}\n\`\`\`\n`;
    else if (t === 'callout') out += `${indent}> ${rt}\n`;
    else if (t === 'table_row') {
      const cells = (b.table_row.cells || []).map(c => c.map(x => x.plain_text || '').join('')).join(' | ');
      out += `${indent}| ${cells} |\n`;
    } else if (rt) {
      out += `${indent}${rt}\n`;
    } else if (t === 'child_page' || t === 'synced_block' || t === 'column_list' || t === 'column' || t === 'table' || t === 'unsupported') {
      // these block types contain content only via children — handled below
      out += `${indent}[${t}]\n`;
    }
  }
  return out;
}

const meeting = $('Pick grandchild block').item.json.meeting;
const topBlocks = $('Pick grandchild block').item.json.top_blocks || [];
const l2Blocks = $('Pick grandchild block').item.json.l2_blocks || [];
const childBlockId = $('Pick child block').item.json.child_block_id;
const grandchildBlockId = $('Pick grandchild block').item.json.grandchild_block_id;
const l3Response = $json || {};
const l3Blocks = l3Response.results || [];

// Build combined text from all levels we reached.
let bodyText = blocksToText(topBlocks, 0);
if (childBlockId) {
  bodyText += '\n\n---\n[L2 transcription children]\n' + blocksToText(l2Blocks, 0);
}
if (grandchildBlockId) {
  bodyText += '\n\n---\n[L3 summary content]\n' + blocksToText(l3Blocks, 0);
}

const hasChildrenIds = topBlocks.filter(b => b.has_children).map(b => `${b.type}:${b.id}`);

const isRecall = meeting.side === 'recall';
const src = isRecall ? 'HiDock field recording (Recall)' : 'Calendar Zoom/Meet (Notion AI Notetaker)';

const prompt = `You are extracting action items from a meeting record.

Meeting title: ${meeting.title}
Meeting date: ${meeting.start_iso || 'unknown'}
Meeting attendees: ${meeting.attendees || 'unknown'}
Meeting company: ${meeting.company || ''}
Source: ${src}

Meeting body (markdown):

${bodyText.slice(0, 30000)}

---

Extract every action item from this meeting. For each, identify:
- text: the action item rewritten as a concise imperative (≤120 chars)
- owner: "Sales User" if Sales User is responsible, else the named other person, else "Unassigned"
- due_date: ISO date YYYY-MM-DD if mentioned, else null
- context: one short phrase (≤80 chars) explaining what the AI relates to

Rules:
- Skip open questions, FYIs, and informational items. An action item must have a clear deliverable.
- If the page has a structured "## Actions" table or "### Action Items" section, those are authoritative.
- Do NOT invent action items not present in the text.

Also classify the meeting into ONE of these projects (or "Other"):
- Example Company Pipeline
- Example Company Business Development
- Corporate Development
- Content
- Operations
- Personal
- Non-Sales Admin
- Other

Return ONLY JSON, no prose:

{
  "project": "<one of the above>",
  "summary": "<one-sentence summary of what the meeting was about, ≤180 chars>",
  "action_items": [
    {"text": "...", "owner": "Sales User", "due_date": null, "context": "..."}
  ]
}`;

return { meeting, body_length: bodyText.length, has_children_blocks: hasChildrenIds, prompt };

// Parse Anthropic response, build Open Tasks page payload. Run once per item.

const meeting = $('Build prompt').item.json.meeting;
const llm = $json || {};

let extracted = null;
let error = null;
try {
  const text = (llm.content || []).map(c => c.text || '').join('');
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('no JSON in response: ' + text.slice(0, 300));
  extracted = JSON.parse(jsonMatch[0]);
} catch (e) {
  error = e.message;
}

if (error || !extracted) {
  return { skip: true, reason: error || 'parse failed', meeting };
}

const ais = (extracted.action_items || []).filter(a => a && a.text && a.text.trim());
if (ais.length === 0) {
  return { skip: true, reason: 'no AIs extracted', meeting, summary: extracted.summary };
}

const meetingDate = (meeting.start_iso || '').slice(0, 10) || 'no date';
const ownerSet = [...new Set(ais.map(a => a.owner || 'Unassigned'))];
const titleBase = (((ais[0] || {}).text || '').trim() + (ais.length > 1 ? ' (+' + (ais.length - 1) + ' more)' : '')).slice(0, 190);

const notesLines = [];
notesLines.push(`Source URL: ${meeting.notion_url}`);
if (meeting.paired_with_url) notesLines.push(`Paired with: ${meeting.paired_with_url}`);
notesLines.push(`Meeting date: ${meetingDate}`);
notesLines.push(`Attendees: ${(meeting.attendees || '').slice(0, 200)}`);
notesLines.push(`Summary: ${extracted.summary || ''}`);
notesLines.push('');
notesLines.push('Action items:');
for (const a of ais) {
  const due = a.due_date ? ` (due ${a.due_date})` : '';
  notesLines.push(`- [${a.owner || 'Unassigned'}] ${a.text}${due}${a.context ? ` — ${a.context}` : ''}`);
}
const notesText = notesLines.join('\n').slice(0, 1990);

const validProjects = new Set(['Example Company Pipeline','Example Company Business Development','Corporate Development','Content','Operations','Personal','Non-Sales Admin']);
const projectName = validProjects.has(extracted.project) ? extracted.project : null;

const properties = {
  Task: { title: [{ text: { content: titleBase } }] },
  Status: { status: { name: 'Not started' } },
  Source: { rich_text: [{ text: { content: `Meeting: ${meeting.title}`.slice(0, 190) } }] },
  Notes: { rich_text: [{ text: { content: notesText } }] },
};
if (projectName) properties.Project = { select: { name: projectName } };

return {
  skip: false,
  meeting,
  ai_count: ais.length,
  owners: ownerSet,
  notion_payload: {
    parent: { data_source_id: 'REPLACE_WITH_DATA_SOURCE_ID' },
    properties,
  },
  preview: { title: titleBase, notes: notesText.slice(0, 300) },
};

// Pass through only items whose Parse step produced a notion_payload.
const out = [];
for (const item of $input.all()) {
  if (item.json && item.json.notion_payload && !item.json.skip) {
    out.push({ json: item.json });
  }
}
return out;

// Aggregate all branches into a final summary
const created = $input.all().map(i => i.json);
const plan = $('Plan harvest').first().json;

const summary = {
  meetings_planned: plan.to_process_count,
  meetings_skipped_at_plan: plan.skipped_count,
  rows_created: created.length,
  generated_at: new Date().toISOString(),
};

return { summary, plan_skipped: plan.skipped, created };
